// AUTO-GENERATED by @aquila/stories compiler. Do not edit by hand.

import type { DialogueEntry } from '../../../types';
import { CharacterId } from '../characters';
import { Portrait } from '../portraits';
import { Background } from '../backgrounds';

export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "18:35。會議室裡大約八到十個人。", background: Background.Chapter_11_Ch11_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "燈沒有調暗。投影幕空白。桌面上的資料夾封面朝下。沒有人急著翻開任何東西。", background: Background.Chapter_11_Ch11_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "房間很普通。也很疲憊。", background: Background.Chapter_11_Ch11_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "桌上散著便利店飯糰的包裝紙。有人帶了校服照片，放在資料夾旁邊，照片朝上。一張醫院繳費單被壓在紙杯下面。透明套裝插著一張學生交通卡。一件反光工作背心掛在椅背上。一個透明夾鏈袋裡裝著孩子沒用完的藥，標籤還在。有人把紙本排班表攤在膝上，用鉛筆在格子裡算著什麼。", background: Background.Chapter_11_Ch11_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯這些不是證物。這些是生活。每一樣東西都還黏著一個沒有回來的孩子的日常。交通卡。藥。校服。繳費單。像有人隨時準備接他們回來，所以這些東西不能收。", background: Background.Chapter_11_Ch11_Act3_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "水瀨佳乃站在桌邊。她沒有介紹澪的全名。", background: Background.Chapter_11_Ch11_Act3_S0 },
    { characterId: CharacterId.MinaseYoshino, character: "水瀨佳乃", dialogue: "這是另一個失蹤孩子的姐姐。", background: Background.Chapter_11_Ch11_Act3_S0, portrait: Portrait.MinaseYoshino_Guarded },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "就這樣。沒有姓。沒有弟弟的名字。沒有背景。", background: Background.Chapter_11_Ch11_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯她只說「姐姐」。不是「朝倉澪」。不是「悠真的姐姐」。是「另一個失蹤孩子的姐姐」。代號。不是名字。", background: Background.Chapter_11_Ch11_Act3_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "桌對面有一個男人。四十多歲。短髮。鬢角灰了。體格結實。穿深色外套，裡面是 polo 衫。臉上有一種很直接的、不浪費表情的樣子。他看著澪。不是打量。是核對。", background: Background.Chapter_11_Ch11_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他沒有先問圖畫內容。", background: Background.Chapter_11_Ch11_Act3_S0 },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "妳何時第一次看見悠真的黑色海？", background: Background.Chapter_11_Ch11_Act3_S0, portrait: Portrait.SaekiTatsuya_Guarded },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "前天。整理他房間的時候。在他的筆記本裡。", background: Background.Chapter_11_Ch11_Act3_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "妳何時看見水瀨葵的圖？", background: Background.Chapter_11_Ch11_Act3_S0, portrait: Portrait.SaekiTatsuya_Guarded },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "昨天。水瀨女士拿出來的。影印紙。", background: Background.Chapter_11_Ch11_Act3_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "佐伯達也沒有點頭。也沒有搖頭。他在紙上寫了兩個日期。", background: Background.Chapter_11_Ch11_Act3_S0 },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "妳在看葵的圖以前，已經知道哪些細節？", background: Background.Chapter_11_Ch11_Act3_S0, portrait: Portrait.SaekiTatsuya_Guarded },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "黑色海。倒過來的月亮。七條線。遠處有亮光。悠真說過「那邊會亮」。", background: Background.Chapter_11_Ch11_Act3_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "妳是否看過其他家庭的圖片或逐字稿？", background: Background.Chapter_11_Ch11_Act3_S0, portrait: Portrait.SaekiTatsuya_Guarded },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "沒有。只看過悠真的，和水瀨葵的。", background: Background.Chapter_11_Ch11_Act3_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "no_moon 對妳說過哪些詞？", background: Background.Chapter_11_Ch11_Act3_S0, portrait: Portrait.SaekiTatsuya_Guarded },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "⋯⋯它問我是不是悠真的姐姐。它說「帶上悠真留下的那件東西」。沒有直接說鏡子。", background: Background.Chapter_11_Ch11_Act3_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "佐伯達也寫完最後一行。放下筆。他看著澪。眼神沒有變軟。也沒有變冷。只是確認。", background: Background.Chapter_11_Ch11_Act3_S0 },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "妳昨天已經看過葵的圖。所以妳現在說的「倒月、七條線」，我不當成新的獨立證據。", background: Background.Chapter_11_Ch11_Act3_S0, portrait: Portrait.SaekiTatsuya_Guarded },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯他知道。他知道我已經被污染了。不是惡意的污染。只是看過了。看過了就沒辦法當作沒看過。他不是在指控我。他是在把我的證詞放對位置。", background: Background.Chapter_11_Ch11_Act3_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他從桌上拿出一張空白卡片。推到澪面前。", background: Background.Chapter_11_Ch11_Act3_S0 },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "分兩欄寫。左邊，看水瀨葵圖以前已知道的。右邊，看過葵圖以後才知道的。", background: Background.Chapter_11_Ch11_Act3_S0, portrait: Portrait.SaekiTatsuya_Guarded },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪拿起筆。", background: Background.Chapter_11_Ch11_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "左欄。她寫：悠真黑色海。倒月。線條。遠處亮光。夢話「那邊會亮」。", background: Background.Chapter_11_Ch11_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "右欄。她寫：葵圖的具體線條間距。月亮位置。", background: Background.Chapter_11_Ch11_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯左邊是我的。右邊是看過她的東西以後才有的。分開。不能混。", background: Background.Chapter_11_Ch11_Act3_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她放下筆。佐伯達也拿走卡片。放在自己面前。沒有念出來。沒有展示給其他人看。只是收著。", background: Background.Chapter_11_Ch11_Act3_S0 },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "現在口頭說一遍。悠真原本的圖。和夢話。", background: Background.Chapter_11_Ch11_Act3_S0, portrait: Portrait.SaekiTatsuya_Guarded },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "黑色海。佔滿整張紙。不像水。沒有反光。月亮倒過來。七條直線從海面延伸出去。不是波浪。是直的。像被什麼東西從底下頂上來。", background: Background.Chapter_11_Ch11_Act3_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "夢話。他睡著的時候說的。「那邊會亮。」重複過幾次。我以前以為是普通夢話。", background: Background.Chapter_11_Ch11_Act3_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "佐伯達也一邊聽一邊寫。他只記錄。沒有說「又一個共同案例」。沒有說「和葵的一樣」。沒有任何宣布。", background: Background.Chapter_11_Ch11_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯他不急著下結論。他在建基線。先把我知道什麼、何時知道、從哪裡知道的全部釘死。然後才能比較。不是先比較再解釋。是先分清楚再比。", background: Background.Chapter_11_Ch11_Act3_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "房間裡很安靜。不是儀式式的安靜。是那種所有人都聽過太多遍、知道接下來要做什麼的安靜。", background: Background.Chapter_11_Ch11_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後有一個聲音。很輕。從桌子的另一側傳過來。", background: Background.Chapter_11_Ch11_Act3_S0 },
    { characterId: CharacterId.FujikawaMari, character: "藤川真理", dialogue: "至少海是真的一樣。", background: Background.Chapter_11_Ch11_Act3_S0, portrait: Portrait.FujikawaMari_Sad },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪轉頭。說話的是一個女人。三十多歲。頭髮鬆鬆的。穿一件褪色的毛衣。眼下的影子很深。她的手放在桌面上，手指壓著一個透明夾鏈袋，裡面裝著什麼藥的剩餘份。", background: Background.Chapter_11_Ch11_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯她女兒。她就是那個——身體回來了，意識沒有回來的那個。", background: Background.Chapter_11_Ch11_Act3_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "像，不等於來源一樣。先把妳看過什麼分清楚。", background: Background.Chapter_11_Ch11_Act3_S0, portrait: Portrait.SaekiTatsuya_Guarded },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他的語氣不重。但很硬。像在釘釘子。", background: Background.Chapter_11_Ch11_Act3_S0 },
    { characterId: CharacterId.FujikawaMari, character: "藤川真理", dialogue: "⋯⋯", background: Background.Chapter_11_Ch11_Act3_S0, portrait: Portrait.FujikawaMari_Sad },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "藤川真理沒有再說。她低下頭。手指在夾鏈袋上鬆開了。", background: Background.Chapter_11_Ch11_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯他不是冷血。他在保護她。也在保護這個房間裡的所有人。如果每個人都因為「海是一樣的」就跳到「我們的孩子都去了同一個地方」，那這個房間就會變成他最害怕的樣子。一個等奇蹟的教派。然後警方就有理由繼續忽略他們。", background: Background.Chapter_11_Ch11_Act3_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "佐伯達也把筆放下。他看了一圈房間裡的人。然後他看著澪。", background: Background.Chapter_11_Ch11_Act3_S0 },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "別把這裡當成全部案例。", background: Background.Chapter_11_Ch11_Act3_S0, portrait: Portrait.SaekiTatsuya_Guarded },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他停了一下。像在選字。", background: Background.Chapter_11_Ch11_Act3_S0 },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "我們只是手上剛好有相似材料、願意留下資料，而且最後找到彼此的人。", background: Background.Chapter_11_Ch11_Act3_S0, portrait: Portrait.SaekiTatsuya_Guarded },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "不能因為這個房間裡的人都畫過海，就說所有失蹤孩子都畫過海。", background: Background.Chapter_11_Ch11_Act3_S0, portrait: Portrait.SaekiTatsuya_Guarded },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯⋯⋯選擇偏差。", background: Background.Chapter_11_Ch11_Act3_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她聽懂了。這個房間不是隨機樣本。是篩選過的。有相似材料的。願意整理的。最後互相找到的。那些沒有畫過海的家屬不會在這裡。那些畫了但不願意分享的不會在這裡。那些根本不知道有其他人的也不會在這裡。", background: Background.Chapter_11_Ch11_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯所以這個房間裡的共同性，不能直接推回全部失蹤案例。他知道的。他在提醒所有人。也在提醒我。", background: Background.Chapter_11_Ch11_Act3_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "房間裡沒有人反駁他。也沒有人顯得受傷。他們聽過了。不只一次。", background: Background.Chapter_11_Ch11_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "有人把飯糰的包裝紙揉成一團，塞進口袋。有人翻了一頁排班表。有人把交通卡的透明套轉了一個方向，讓卡面朝上，看了一眼，又翻回去。", background: Background.Chapter_11_Ch11_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "19:05。佐伯達也把那張卡片收進自己的資料夾。他沒有宣布任何結論。他只說了一句。", background: Background.Chapter_11_Ch11_Act3_S0 },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "基線記完了。接下來看材料。", background: Background.Chapter_11_Ch11_Act3_S0, portrait: Portrait.SaekiTatsuya_Guarded },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他伸手去翻桌上那個封面朝下的資料夾。", background: Background.Chapter_11_Ch11_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪看著他的手。資料夾是灰色的。很普通。像文具店買的那種。", background: Background.Chapter_11_Ch11_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯他先確認了我看過什麼。先把我已知的和後來知道的分開。先承認了這個房間的偏差。然後才翻開資料夾。", background: Background.Chapter_11_Ch11_Act3_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯順序是對的。順序是反過來的。不是先看圖再說「我們都一樣」。是先說清楚每個人從哪裡來、帶了什麼、被污染了多少。然後才看。", background: Background.Chapter_11_Ch11_Act3_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她的手放在膝蓋上。背包裡有鏡背的照片、描圖和筆記。原件鎖在家裡的抽屜。", background: Background.Chapter_11_Ch11_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她還沒有拿出來。她在等。等看完這個資料夾裡有什麼。等確認這個房間到底是不是她以為的地方。", background: Background.Chapter_11_Ch11_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "燈還是正常亮度。投影幕還是空白。房間裡的人還是那些疲憊的、帶著飯糰和排班表和交通卡的人。", background: Background.Chapter_11_Ch11_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後佐伯達也翻開了封面。", background: Background.Chapter_11_Ch11_Act3_S0 },
];
